let story;

try {
  const sceneObject = items[0].json.message.content;
  if (sceneObject && typeof sceneObject === "object") {
    story = Object.entries(sceneObject)
      .filter(([key, value]) => key.startsWith("Scene"))
      .map(([key, value]) => value); // <<<< ADD THIS .map() TO GET ONLY SCENE TEXTS
  } else {
    throw new Error("No valid scene object found.");
  }
} catch (e2) {
  throw new Error("Could not extract scenes properly.");
}

let output = [];

for (const scene of story) {
  output.push({ description: scene });
}

return output;

